// Extract text từ DOCX bằng cách đọc XML bên trong (DOCX = ZIP file)
// Không cần thư viện ngoài - chỉ dùng built-in Buffer

const item = $input.first();
const binaryKey = item.binary ? Object.keys(item.binary)[0] : 'data';
const binaryData = item.binary?.[binaryKey];

if (!binaryData) {
  return [{ json: { ...item.json, text: 'Không có binary data' } }];
}

try {
  // Convert base64 → string, tìm text trong XML của docx
  const base64 = binaryData.data;
  const raw = Buffer.from(base64, 'base64').toString('binary');

  // DOCX là ZIP, tìm phần word/document.xml và extract text giữa các tag XML
  // Tìm đoạn text giữa <w:t> tags
  const matches = raw.match(/<w:t[^>]*>([^<]+)<\/w:t>/g) || [];
  const text = matches
    .map(m => m.replace(/<w:t[^>]*>/g, '').replace(/<\/w:t>/g, ''))
    .join(' ')
    .replace(/\s+/g, ' ')
    .trim();

  return [{
    json: {
      ...item.json,
      text: text.slice(0, 5000) || ('Tên file: ' + (item.json.name || ''))
    },
    binary: item.binary
  }];
} catch(err) {
  return [{
    json: {
      ...item.json,
      text: 'Tên file: ' + (item.json.name || '')
    },
    binary: item.binary
  }];
}

// 1. Lấy output từ AI
const aiRawOutput = $input.first().json.output || '';

// 2. Parse JSON AI
let parsedAI;
try {
  const clean = aiRawOutput.replace(/```json|```/g, '').trim();
  parsedAI = JSON.parse(clean);
} catch (e) {
  parsedAI = { category: 'Khác', confidence: 0.3, reason: 'Lỗi parse' };
}

// 3. Lấy thông tin FILE từ node "Download File"
let fileId = '';
let fileName = '';
let miniType = ''; 

try {
  // Tìm node Download File
  const downloadNode = $('Download File').first();

  if (downloadNode) {
    fileId = downloadNode.json.id || '';
    fileName = downloadNode.json.name || '';

    // CỐ GẮNG LẤY mimeType TỪ NHIỀU NGUỒN KHÁC NHAU
    // n8n Google Drive node thường để ở json.mimeType hoặc trong binary
    miniType = downloadNode.json.mimeType || 
               (downloadNode.binary && downloadNode.binary.data ? downloadNode.binary.data.mimeType : '');

    // Nếu vẫn trống, thử đoán dựa trên đuôi file (Dành cho docx, pdf, xlsx)
    if (!miniType && fileName.includes('.')) {
      const ext = fileName.split('.').pop().toLowerCase();
      const mimeMap = {
        'docx': 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
        'pdf': 'application/pdf',
        'xlsx': 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
        'jpg': 'image/jpeg',
        'png': 'image/png'
      };
      miniType = mimeMap[ext] || 'unknown/' + ext;
    }
  }
} catch (err) {
  fileId = 'N/A';
}

// 4. Trả về kết quả
return [{
  json: {
    category: parsedAI.category || 'Khác',
    confidence: parsedAI.confidence || 0,
    reason: parsedAI.reason || '',
    fileId: fileId,
    fileName: fileName,
    miniType: miniType || 'application/octet-stream', // Nếu không tìm thấy thì để mặc định
    processedAt: new Date().toLocaleString('vi-VN'),
    source: 'n8n_system'
  }
}];

const item = $input.first();
const binaryData = item.binary.data;

return [{
  json: {
    fileName: item.json.name || "document.png",
    imageBase64: binaryData.data,
    mimeType: binaryData.mimeType
  }
}];

